#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const CONFIG = {
  NODE_ENV: process.env.NODE_ENV || 'production',
  DEPLOY_TARGET: process.env.DEPLOY_TARGET || '',
  DEPLOY_KEY: process.env.DEPLOY_KEY || '',
  SKIP_TESTS: process.env.SKIP_TESTS === 'true',
  PARALLEL_JOBS: parseInt(process.env.PARALLEL_JOBS || '4', 10),
  BUILD_CACHE_DIR: process.env.BUILD_CACHE_DIR || '.build-cache',
  DEPLOY_TIMEOUT: parseInt(process.env.DEPLOY_TIMEOUT || '300000', 10),
  ROLLBACK_ON_FAILURE: process.env.ROLLBACK_ON_FAILURE !== 'false',
  HEALTH_CHECK_URL: process.env.HEALTH_CHECK_URL || '',
  HEALTH_CHECK_RETRIES: parseInt(process.env.HEALTH_CHECK_RETRIES || '5', 10),
  ARTIFACT_DIR: process.env.ARTIFACT_DIR || 'dist',
  LOG_FILE: process.env.LOG_FILE || 'deploy.log'
};

const ALLOWED_DEPLOY_TARGETS = ['production', 'staging', 'development'];

class Logger {
  constructor(logFile) {
    this.logFile = logFile;
    this.logStream = fs.createWriteStream(logFile, { flags: 'a' });
  }

  log(level, message) {
    const timestamp = new Date().toISOString();
    const logMessage = `[${timestamp}] [${level}] ${message}\n`;
    process.stdout.write(logMessage);
    this.logStream.write(logMessage);
  }

  info(message) { this.log('INFO', message); }
  error(message) { this.log('ERROR', message); }
  warn(message) { this.log('WARN', message); }
  success(message) { this.log('SUCCESS', message); }

  close() {
    this.logStream.end();
  }
}

class CIPipeline {
  constructor(config, logger) {
    this.config = config;
    this.logger = logger;
    this.startTime = Date.now();
    this.previousDeploymentHash = null;
  }

  validateConfig() {
    this.logger.info('Validating configuration...');

    if (!this.config.DEPLOY_TARGET) {
      throw new Error('DEPLOY_TARGET environment variable is required');
    }

    if (!ALLOWED_DEPLOY_TARGETS.includes(this.config.DEPLOY_TARGET)) {
      throw new Error(`Invalid DEPLOY_TARGET. Must be one of: ${ALLOWED_DEPLOY_TARGETS.join(', ')}`);
    }

    if (!this.config.DEPLOY_KEY || this.config.DEPLOY_KEY.length < 32) {
      throw new Error('DEPLOY_KEY must be set and at least 32 characters');
    }

    if (!fs.existsSync('package.json')) {
      throw new Error('package.json not found in current directory');
    }

    this.logger.success('Configuration validated');
  }

  exec(command, options = {}) {
    try {
      const result = execSync(command, {
        stdio: options.silent ? 'pipe' : 'inherit',
        encoding: 'utf-8',
        maxBuffer: 50 * 1024 * 1024,
        ...options
      });
      return result;
    } catch (error) {
      this.logger.error(`Command failed: ${command}`);
      throw error;
    }
  }

  calculateChecksum(directory) {
    const hash = crypto.createHash('sha256');
    const files = this.getAllFiles(directory);
    
    files.sort().forEach(file => {
      const content = fs.readFileSync(file);
      hash.update(content);
    });

    return hash.digest('hex');
  }

  getAllFiles(dir, fileList = []) {
    if (!fs.existsSync(dir)) return fileList;

    const files = fs.readdirSync(dir);
    files.forEach(file => {
      const filePath = path.join(dir, file);
      if (fs.statSync(filePath).isDirectory()) {
        if (!file.startsWith('.') && file !== 'node_modules') {
          this.getAllFiles(filePath, fileList);
        }
      } else {
        fileList.push(filePath);
      }
    });

    return fileList;
  }

  installDependencies() {
    this.logger.info('Installing dependencies...');
    const startTime = Date.now();

    const packageLockExists = fs.existsSync('package-lock.json');
    const yarnLockExists = fs.existsSync('yarn.lock');
    const pnpmLockExists = fs.existsSync('pnpm-lock.yaml');

    if (pnpmLockExists) {
      this.exec('pnpm install --frozen-lockfile --prefer-offline');
    } else if (yarnLockExists) {
      this.exec('yarn install --frozen-lockfile --prefer-offline');
    } else if (packageLockExists) {
      this.exec('npm ci --prefer-offline');
    } else {
      this.logger.warn('No lock file found, using npm install');
      this.exec('npm install --prefer-offline');
    }

    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    this.logger.success(`Dependencies installed in ${duration}s`);
  }

  runTests() {
    if (this.config.SKIP_TESTS) {
      this.logger.warn('Skipping tests (SKIP_TESTS=true)');
      return;
    }

    this.logger.info('Running tests...');
    const startTime = Date.now();

    try {
      const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
      
      if (packageJson.scripts && packageJson.scripts.test) {
        this.exec('npm test -- --maxWorkers=' + this.config.PARALLEL_JOBS);
      } else {
        this.logger.warn('No test script found in package.json');
      }

      const duration = ((Date.now() - startTime) / 1000).toFixed(2);
      this.logger.success(`Tests passed in ${duration}s`);
    } catch (error) {
      this.logger.error('Tests failed');
      throw error;
    }
  }

  buildApplication() {
    this.logger.info('Building application...');
    const startTime = Date.now();

    const cacheDir = this.config.BUILD_CACHE_DIR;
    if (!fs.existsSync(cacheDir)) {
      fs.mkdirSync(cacheDir, { recursive: true });
    }

    const sourceChecksum = this.calculateChecksum('src');
    const cacheFile = path.join(cacheDir, `build-${sourceChecksum}.tar.gz`);

    if (fs.existsSync(cacheFile)) {
      this.logger.info('Using cached build...');
      this.exec(`tar -xzf ${cacheFile}`);
      const duration = ((Date.now() - startTime) / 1000).toFixed(2);
      this.logger.success(`Build restored from cache in ${duration}s`);
      return;
    }

    const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    
    if (packageJson.scripts && packageJson.scripts.build) {
      this.exec(`NODE_ENV=${this.config.NODE_ENV} npm run build`);
    } else {
      this.logger.warn('No build script found in package.json');
    }

    if (fs.existsSync(this.config.ARTIFACT_DIR)) {
      this.exec(`tar -czf ${cacheFile} ${this.config.ARTIFACT_DIR}`);
      this.logger.info('Build cached for future use');
    }

    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    this.logger.success(`Application built in ${duration}s`);
  }

  createDeploymentPackage() {
    this.logger.info('Creating deployment package...');
    
    const deployDir = 'deploy-package';
    if (fs.existsSync(deployDir)) {
      fs.rmSync(deployDir, { recursive: true, force: true });
    }
    fs.mkdirSync(deployDir, { recursive: true });

    if (fs.existsSync(this.config.ARTIFACT_DIR)) {
      this.exec(`cp -r ${this.config.ARTIFACT_DIR}/* ${deployDir}/`);
    }

    const essentialFiles = ['package.json', 'package-lock.json', 'yarn.lock', 'pnpm-lock.yaml'];
    essentialFiles.forEach(file => {
      if (fs.existsSync(file)) {
        fs.copyFileSync(file, path.join(deployDir, file));
      }
    });

    const deploymentHash = this.calculateChecksum(deployDir);
    fs.writeFileSync(
      path.join(deployDir, 'deployment.json'),
      JSON.stringify({
        hash: deploymentHash,
        timestamp: new Date().toISOString(),
        target: this.config.DEPLOY_TARGET,
        version: JSON.parse(fs.readFileSync('package.json', 'utf-8')).version
      }, null, 2)
    );

    this.logger.success('Deployment package created');
    return deploymentHash;
  }

  async healthCheck() {
    if (!this.config.HEALTH_CHECK_URL) {
      this.logger.warn('No HEALTH_CHECK_URL configured, skipping health check');
      return true;
    }

    this.logger.info('Performing health check...');
    
    for (let i = 0; i < this.config.HEALTH_CHECK_RETRIES; i++) {
      try {
        const https = require('https');
        const http = require('http');
        const url = new URL(this.config.HEALTH_CHECK_URL);
        const client = url.protocol === 'https:' ? https : http;

        await new Promise((resolve, reject) => {
          const req = client.get(this.config.HEALTH_CHECK_URL, { timeout: 5000 }, (res) => {
            if (res.statusCode >= 200 && res.statusCode < 300) {
              resolve();
            } else {
              reject(new Error(`Health check failed with status ${res.statusCode}`));
            }
          });

          req.on('error', reject);
          req.on('timeout', () => {
            req.destroy();
            reject(new Error('Health check timeout'));
          });
        });

        this.logger.success('Health check passed');
        return true;
      } catch (error) {
        this.logger.warn(`Health check attempt ${i + 1} failed: ${error.message}`);
        if (i < this.config.HEALTH_CHECK_RETRIES - 1) {
          await new Promise(resolve => setTimeout(resolve, 5000));
        }
      }
    }

    throw new Error('Health check failed after all retries');
  }

  deploy() {
    this.logger.info(`Deploying to ${this.config.DEPLOY_TARGET}...`);
    const startTime = Date.now();

    const deployScript = `./deploy-${this.config.DEPLOY_TARGET}.sh`;
    
    if (!fs.existsSync(deployScript)) {
      this.logger.warn(`Deploy script ${deployScript} not found, using generic deployment`);
      this.genericDeploy();
    } else {
      const stats = fs.statSync(deployScript);
      if ((stats.mode & 0o111) === 0) {
        throw new Error(`Deploy script ${deployScript} is not executable`);
      }

      this.exec(`${deployScript} deploy-package`, {
        env: {
          ...process.env,
          DEPLOY_KEY: this.config.DEPLOY_KEY,
          DEPLOY_TARGET: this.config.DEPLOY_TARGET
        },
        timeout: this.config.DEPLOY_TIMEOUT
      });
    }

    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    this.logger.success(`Deployed to ${this.config.DEPLOY_TARGET} in ${duration}s`);
  }

  genericDeploy() {
    this.logger.info('Executing generic deployment...');
    
    const deployDir = process.env.DEPLOY_DIR || '/var/www/app';
    const backupDir = `${deployDir}.backup`;

    if (fs.existsSync(deployDir)) {
      if (fs.existsSync(backupDir)) {
        fs.rmSync(backupDir, { recursive: true, force: true });
      }
      fs.renameSync(deployDir, backupDir);
      this.previousDeploymentHash = this.calculateChecksum(backupDir);
    }

    this.exec(`cp -r deploy-package ${deployDir}`);
    this.logger.success('Generic deployment completed');
  }

  rollback() {
    if (!this.config.ROLLBACK_ON_FAILURE) {
      this.logger.warn('Rollback disabled (ROLLBACK_ON_FAILURE=false)');
      return;
    }

    this.logger.warn('Initiating rollback...');
    
    const deployDir = process.env.DEPLOY_DIR || '/var/www/app';
    const backupDir = `${deployDir}.backup`;

    if (fs.existsSync(backupDir)) {
      if (fs.existsSync(deployDir)) {
        fs.rmSync(deployDir, { recursive: true, force: true });
      }
      fs.renameSync(backupDir, deployDir);
      this.logger.success('Rollback completed');
    } else {
      this.logger.error('No backup found for rollback');
    }
  }

  cleanup() {
    this.logger.info('Cleaning up...');

    const tempDirs = ['deploy-package'];
    tempDirs.forEach(dir => {
      if (fs.existsSync(dir)) {
        fs.rmSync(dir, { recursive: true, force: true });
      }
    });

    const cacheDir = this.config.BUILD_CACHE_DIR;
    if (fs.existsSync(cacheDir)) {
      const cacheFiles = fs.readdirSync(cacheDir);
      const now = Date.now();
      const maxAge = 7 * 24 * 60 * 60 * 1000;

      cacheFiles.forEach(file => {
        const filePath = path.join(cacheDir, file);
        const stats = fs.statSync(filePath);
        if (now - stats.mtimeMs > maxAge) {
          fs.unlinkSync(filePath);
          this.logger.info(`Removed old cache file: ${file}`);
        }
      });
    }

    this.logger.success('Cleanup completed');
  }

  async run() {
    try {
      this.logger.info('=== CI/CD Pipeline Started ===');
      
      this.validateConfig();
      this.installDependencies();
      this.runTests();
      this.buildApplication();
      const deploymentHash = this.createDeploymentPackage();
      this.deploy();
      await this.healthCheck();
      this.cleanup();

      const totalDuration = ((Date.now() - this.startTime) / 1000).toFixed(2);
      this.logger.success(`=== Pipeline Completed Successfully in ${totalDuration}s ===`);
      this.logger.info(`Deployment hash: ${deploymentHash}`);
      
      process.exit(0);
    } catch (error) {
      this.logger.error(`Pipeline failed: ${error.message}`);
      
      try {
        this.rollback();
      } catch (rollbackError) {
        this.logger.error(`Rollback failed: ${rollbackError.message}`);
      }

      const totalDuration = ((Date.now() - this.startTime) / 1000).toFixed(2);
      this.logger.error(`=== Pipeline Failed after ${totalDuration}s ===`);
      
      process.exit(1);
    } finally {
      this.logger.close();
    }
  }
}

